import { TranslateModule, TranslateLoader } from '@ngx-translate/core';
import { provideToastr } from 'ngx-toastr';
import { provideAnimationsAsync } from '@angular/platform-browser/animations/async';

export const appConfig: ApplicationConfig = {
  providers: [
    // ... existing providers
    provideAnimationsAsync(),  // Required by ngx-toastr and ng-bootstrap (async = non-blocking)
    importProvidersFrom(
      TranslateModule.forRoot({
        loader: { provide: TranslateLoader, useClass: HttpTranslationLoader },
      }),
    ),
    provideToastr({
      positionClass: 'toast-bottom-right',
      timeOut: 3000,
      extendedTimeOut: 1500,
      preventDuplicates: true,
      progressBar: true,
    }),
  ],
};

import { provideExperimentalZonelessChangeDetection } from '@angular/core';

export const appConfig: ApplicationConfig = {
    providers: [
        provideExperimentalZonelessChangeDetection(),
        // ... other providers (remove provideZoneChangeDetection if present)
    ]
};

// In feature service
get(id: string): Promise<ActionDTO> {
  return firstValueFrom(this.http.get<ActionDTO>(`${this.apiBase}/${id}`));
}

// In component
readonly data = signal<ActionDTO | null>(null);

constructor() {
  effect(() => {
    const id = this.id();
    if (id) {
      this.service.get(id).then(d => this.data.set(d));
    }
  });
}

// In component — no service method needed for simple GETs
readonly id = input.required<string>();

readonly resource = httpResource<ActionDTO>(() =>
  this.id() ? `${environment.apiBaseUrl}/api/v1/actions/${this.id()}` : undefined
);

// Template access
@if (resource.value(); as action) {
  <h2>{{ action.name }}</h2>
}
@if (resource.isLoading()) {
  <app-spinner />
}
